glsl3.frag:
precision highp float;
vec4 CCSampleWithAlphaSeparated(sampler2D tex, vec2 uv) {
#if CC_USE_EMBEDDED_ALPHA
  return vec4(texture(tex, uv).rgb, texture(tex, uv + vec2(0.0, 0.5)).r);
#else
  return texture(tex, uv);
#endif
}
#if USE_ALPHA_TEST
  layout(std140) uniform ALPHA_TEST_DATA {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
    if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
    if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 color;
#if USE_TEXTURE
  in vec2 uv0;
  uniform sampler2D cc_spriteTexture;
#endif
layout(std140) uniform FlashConstant {
  vec4 flashColor;
  vec4 fxParams;
  vec4 glowColor;
  vec4 glowParams;
};
vec3 hueRotate (vec3 c, float a) {
  const vec3 k = vec3(0.57735026919);
  float cs = cos(a);
  return c * cs + cross(k, c) * sin(a) + k * dot(k, c) * (1.0 - cs);
}
vec4 frag () {
  vec4 o = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
    o *= CCSampleWithAlphaSeparated(cc_spriteTexture, uv0);
    #if IS_GRAY
      float gray  = 0.2126 * o.r + 0.7152 * o.g + 0.0722 * o.b;
      o.r = o.g = o.b = gray;
    #endif
  #endif
  o *= color;
  #if USE_TEXTURE
  if (glowColor.a > 0.0 && o.a > 0.0039) {
    float q = glowParams.w;
    int RINGS = q < 0.5 ? 2 : (q < 1.5 ? 3 : (q < 2.5 ? 4 : 5));
    int DIRS  = q < 0.5 ? 6 : (q < 1.5 ? 8 : (q < 2.5 ? 12 : 16));
    const int MAX_RINGS = 5;
    const int MAX_DIRS  = 16;
    float g = 0.0;
    for (int r = 1; r <= MAX_RINGS; r++) {
      if (r > RINGS) break;
      float rf = float(r) / float(RINGS);
      float w  = 1.0 - 0.7 * rf;
      vec2 rad = glowParams.xy * rf;
      for (int i = 0; i < MAX_DIRS; i++) {
        if (i >= DIRS) break;
        float ang = 6.2831853 * (float(i) / float(DIRS));
        vec2 off  = vec2(cos(ang), sin(ang)) * rad;
        float sa  = CCSampleWithAlphaSeparated(cc_spriteTexture, uv0 + off).a;
        g = max(g, (1.0 - sa) * w);
      }
    }
    g = pow(clamp(g, 0.0, 1.0), max(0.0001, glowParams.z));
    float rim = g * clamp(glowColor.a, 0.0, 1.0) * o.a;
    o.rgb = mix(o.rgb, glowColor.rgb, rim);
  }
  #endif
  ALPHA_TEST(o);
  if (fxParams.x != 0.0) o.rgb = clamp(hueRotate(o.rgb, fxParams.x), 0.0, 1.0);
  if (fxParams.y > 0.0) {
    float luma = dot(o.rgb, vec3(0.2126, 0.7152, 0.0722));
    o.rgb = mix(o.rgb, vec3(luma), clamp(fxParams.y, 0.0, 1.0));
  }
  o.rgb *= (1.0 - clamp(fxParams.z, 0.0, 1.0));
  o.rgb = mix(o.rgb, flashColor.rgb, clamp(flashColor.a, 0.0, 1.0));
  return o;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

